import json,sys,urllib.request,time,copy,gzip,base64
K=sys.argv[1]; B64=sys.argv[2]; B='https://irynakarmazina.app.n8n.cloud/api/v1/'
deals=json.loads(gzip.decompress(base64.b64decode(B64)).decode('utf-8'))
def call(method,u,data=None):
    h={'X-N8N-API-KEY':K}
    if data is not None: h['Content-Type']='application/json'
    for a in range(8):
        try:
            r=urllib.request.urlopen(urllib.request.Request(B+u,data=data,method=method,headers=h),timeout=20); return r.status,r.read()
        except Exception as e: time.sleep(3)
    return None,b''
mk=json.load(open('/root/mk-backup-JQKA35haUsXU4XqE.json'))
readn=[n for n in mk['nodes'] if n.get('name')=='Читаємо CRM'][0]
writen=[n for n in mk['nodes'] if n.get('name')=='Запис у CRM'][0]
rn=copy.deepcopy(readn); rn['name']='Read'; rn['id']='r1'; rn['position']=[220,0]
wn=copy.deepcopy(writen); wn['name']='Write'; wn['id']='w1'; wn['position']=[900,0]
wn['parameters']['columns']={'mappingMode':'autoMapInputData','matchingColumns':['Угода'],'schema':[]}
# passthrough: read -> code(merge, backup) -> write -> summary -> respond
payload_js=json.dumps(deals,ensure_ascii=False)
mergejs="const J="+payload_js+""";
const cur=$input.all().map(i=>i.json);
const exist=new Set(cur.map(r=>Number(r['Угода'])).filter(x=>!isNaN(x)));
const out=[]; let upd=0,add=0,deliv=0;
for(const d of J){
  const un=Number(d.u); const isNew=!exist.has(un);
  if(isNew){
    const o={'Угода':un,'Клієнт':d.kl,'Тип':d.tp,'Лінія':d.ln,'Агент':d.ag,'BL/Booking':d.bl,'Контейнер':d.c1,'Маршрут':d.mr,'Кількість':d.qt,'Напрямок':d.np,'Лист (джерело)':d.bz};
    if(d.nc>1) o['Контейнер (лінія)']=d.cl;
    if(d.bz==='Завершена'){o['Статус']='Вантаж доставлено';deliv++;}
    out.push({json:o}); add++;
  } else {
    const o={'Угода':un,'Кількість':d.qt};
    if(d.nc>1){o['Контейнер (лінія)']=d.cl; if(d.c1) o['Контейнер']=d.c1;}
    out.push({json:o}); upd++;
  }
}
return [{json:{_stats:{upd,add,deliv,total:out.length}}}, ...out];"""
codeMerge={'parameters':{'jsCode':mergejs},'name':'Merge','type':'n8n-nodes-base.code','typeVersion':2,'position':[440,0],'id':'m1'}
# split off stats item so it is not written
splitjs="return $input.all().filter(x=>!x.json._stats);"
codeSplit={'parameters':{'jsCode':splitjs},'name':'ToWrite','type':'n8n-nodes-base.code','typeVersion':2,'position':[680,0],'id':'sp1'}
summjs="const m=$('Merge').first().json._stats; return [{json:m}];"
codeSumm={'parameters':{'jsCode':summjs},'name':'Summary','type':'n8n-nodes-base.code','typeVersion':2,'position':[1120,0],'id':'su1'}
resp={'parameters':{'respondWith':'json','responseBody':'={{ JSON.stringify($json) }}','options':{}},'name':'Respond','type':'n8n-nodes-base.respondToWebhook','typeVersion':1,'position':[1340,0],'id':'rp1'}
trig={'parameters':{'httpMethod':'POST','path':'claude-import-journal','responseMode':'responseNode','options':{}},'name':'Trigger','type':'n8n-nodes-base.webhook','typeVersion':2,'position':[0,0],'id':'t1','webhookId':'claude-import-journal'}
wf={'name':'ONESHOT import-journal (Claude)','nodes':[trig,rn,codeMerge,codeSplit,wn,codeSumm,resp],'connections':{'Trigger':{'main':[[{'node':'Read','type':'main','index':0}]]},'Read':{'main':[[{'node':'Merge','type':'main','index':0}]]},'Merge':{'main':[[{'node':'ToWrite','type':'main','index':0}]]},'ToWrite':{'main':[[{'node':'Write','type':'main','index':0}]]},'Write':{'main':[[{'node':'Summary','type':'main','index':0}]]},'Summary':{'main':[[{'node':'Respond','type':'main','index':0}]]}},'settings':{'executionOrder':'v1'}}
# backup sheet first: read via a separate quick GET of sheet? use the Read node result is inside workflow; instead do explicit backup by running read through API is not trivial. Do backup by calling a minimal read here:
# We rely on /root/sheet backup done separately below.
st,body=call('POST','workflows',json.dumps(wf).encode())
if st not in (200,201): print('CREATE fail',st,body[:300]); sys.exit()
wid=json.loads(body).get('id'); print('created',wid)
call('POST','workflows/'+wid+'/activate'); time.sleep(4)
import urllib.request as U
try:
    r=U.urlopen(U.Request('https://irynakarmazina.app.n8n.cloud/webhook/claude-import-journal',data=b'{}',method='POST',headers={'Content-Type':'application/json'}),timeout=120)
    print('RESULT:',r.read().decode('utf-8','ignore')[:800])
except Exception as e: print('webhook err',e)
call('DELETE','workflows/'+wid); print('deleted')

PYEOF
